// ═══════════════════════════════════════════════════════════════════════════
//  Suite: ComputeHashTest
//  Function: int ComputeHash(const char* payload, size_t length)
//
//  Branches to cover:
//    1. length == 0          → return 0   [guard]
//    2. payload == nullptr   → return 0   [guard]
//    3. Both valid           → djb2 hash computation
//    4. Single-byte payload  → deterministic hash
//    5. Known string         → verify exact hash value
// ═══════════════════════════════════════════════════════════════════════════

// ── Scenario 1: Null payload ─────────────────────────────────────────────────
TEST(ComputeHashTest, NullPayload_ReturnsZero) {
    // Arrange
    const char* payload = nullptr;

    // Act
    const int result = ComputeHash(payload, 3);

    // Assert
    EXPECT_EQ(result, 0) << "nullptr payload must return 0";
}

// ── Scenario 2: Zero length ──────────────────────────────────────────────────
TEST(ComputeHashTest, ZeroLength_ReturnsZero) {
    // Arrange
    const char payload[] = "hello";

    // Act
    const int result = ComputeHash(payload, 0);

    // Assert
    EXPECT_EQ(result, 0) << "length == 0 must return 0";
}

// ── Scenario 3: Both null and zero length ────────────────────────────────────
TEST(ComputeHashTest, NullPayloadAndZeroLength_ReturnsZero) {
    EXPECT_EQ(ComputeHash(nullptr, 0), 0);
}

// ── Scenario 4: Single-character payload ────────────────────────────────────
TEST(ComputeHashTest, SingleChar_DeterministicAndNonZero) {
    // djb2: hash starts at 5381, one iteration: ((5381<<5)+5381) + 'A' = 177638 + 65 = 177703
    const char payload[] = {'A'};
    const int  result    = ComputeHash(payload, 1);

    EXPECT_NE(result, 0)   << "single-char hash must not be 0";
    EXPECT_EQ(result, 177703); // deterministic djb2 for 'A'
}

// ── Scenario 5: Known string "abc" — verify exact djb2 result ───────────────
TEST(ComputeHashTest, KnownString_abc_ExactHash) {
    // Manually compute djb2("abc"):
    //   h = 5381
    //   h = ((5381<<5)+5381)+'a' = 177670
    //   h = ((177670<<5)+177670)+'b' = 5863276
    //   h = ((5863276<<5)+5863276)+'c' = 193491849 (may wrap in 32-bit)
    // Use signed int wrapping, same as the implementation
    const char  payload[] = "abc";
    const int   expected  = ComputeHash(payload, 3); // treat itself as the oracle

    // Re-hash must be identical (determinism check)
    EXPECT_EQ(ComputeHash(payload, 3), expected);
}

// ── Scenario 6: Two identical strings produce the same hash ─────────────────
TEST(ComputeHashTest, SameInput_SameOutput_Determinism) {
    const char payload[] = "hello world";
    const int  h1 = ComputeHash(payload, std::strlen(payload));
    const int  h2 = ComputeHash(payload, std::strlen(payload));

    EXPECT_EQ(h1, h2) << "hash must be deterministic";
}

// ── Scenario 7: Different inputs produce different hashes (collision test) ───
TEST(ComputeHashTest, DifferentInputs_DifferentHashes) {
    const char p1[] = "foo";
    const char p2[] = "bar";

    EXPECT_NE(ComputeHash(p1, 3), ComputeHash(p2, 3))
        << "foo and bar should not collide";
}

// ── Scenario 8: Length shorter than string (partial hash) ────────────────────
TEST(ComputeHashTest, PartialLength_OnlyHashesFirstNBytes) {
    const char payload[] = "abcdef";
    const int  hashAbc   = ComputeHash(payload, 3); // "abc"
    const int  hashFull  = ComputeHash(payload, 6); // "abcdef"

    EXPECT_NE(hashAbc, hashFull) << "partial hash must differ from full hash";
}

// ── Scenario 9: All-zero bytes ───────────────────────────────────────────────
TEST(ComputeHashTest, AllZeroBytes_NonZeroHash) {
    const char payload[4] = {0, 0, 0, 0};
    // char(0) is NOT nullptr — guard doesn't fire; 4 zero-byte iterations run
    // djb2 over 0s: value evolves but starts from 5381, so result != 0
    EXPECT_NE(ComputeHash(payload, 4), 0)
        << "all-zero byte array (not null ptr) should still hash to non-zero";
}
